  }
}

function colorFor(kind: AssetSymbolKind, paint: ViewportPaintBundle | null | undefined): string {
  switch (kind) {
    case 'fridge':
      return '#e5e7eb';
    case 'oven':
      return '#3f3f46';
    case 'sink':
      return '#c7d2fe';
    case 'bed':
