    case 'fridge':
      addBox(group, pickId, [w, h, d], [0, h / 2, 0], spec.color, 0.45, 0.08);
      addBox(group, pickId, [0.012, h * 0.82, 0.018], [w * 0.18, h * 0.53, frontZ], '#64748b');
      addBox(group, pickId, [w * 0.82, 0.012, 0.018], [0, h * 0.52, frontZ], '#94a3b8');
